import {
  Component,
  inject,
  computed,
  OnDestroy,
  AfterViewInit,
  signal,
  ChangeDetectionStrategy,
  NgZone,
  effect,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { LucideAngularModule } from 'lucide-angular';
import { Router, NavigationEnd } from '@angular/router';
import { filter, take } from 'rxjs/operators';
import { firstValueFrom, Subscription } from 'rxjs';
import { TutorialService } from '../../services/tutorial.service';
import { AuthService } from '../../services/Base/auth.service'; // ← AGGIUNTO
import { TaskService } from '../../services/task.service';
import { StaffRole } from '../guards/permission.service';

interface TooltipPosition {
  top: number;
  left: number;
  arrowSide: 'top' | 'bottom' | 'left' | 'right';
}

@Component({
  selector: 'app-tutorial-tooltip',
  standalone: true,
  imports: [CommonModule, LucideAngularModule],
  templateUrl: './tutorial-tooltip.html',
  styleUrls: ['./tutorial-tooltip.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TutorialTooltip implements AfterViewInit, OnDestroy {
  public tutorial = inject(TutorialService);
  public auth = inject(AuthService); // ← AGGIUNTO
  private zone = inject(NgZone);
  private router = inject(Router);
  private taskService = inject(TaskService);

  public isTooltipPhase = computed(() => this.tutorial.phase() === 'tooltip');
  public tooltipPos = signal<TooltipPosition | null>(null);
  public highlightRect = signal<DOMRect | null>(null);

  private sidebarObserver?: ResizeObserver;
  private resizeObserver?: ResizeObserver;
  private navSubscription?: Subscription;
  private _onScroll?: EventListener;

  constructor() {
    effect(() => {
      const step = this.tutorial.currentStepData();
      const phase = this.tutorial.phase();
      const _ = this.tutorial.refreshSignal();
      const _sub = this.tutorial.currentSubStep();
      const _intro = this.tutorial.isIntroStep();

      if (phase !== 'tooltip' || !step) {
        setTimeout(() => { this.tooltipPos.set(null); this.highlightRect.set(null); }, 0);
        return;
      }

      setTimeout(() => this.navigateAndRecalculate(step), 0);
    });
  }

private async navigateAndRecalculate(step: { id?: string; route?: string; tooltipTarget?: string; tooltipPosition?: string }): Promise<void> {
  if (!step.route) {
    this.recalculate();
    return;
  }

  let targetRoute = step.route;

  // Se lo step è task-detail, dobbiamo ottenere l'ID di una task reale
  if (step.id === 'task-detail') {
    try {
      // Ottieni le task (carica se necessario)
      let tasks = await firstValueFrom(this.taskService.tasksView$);
      if (tasks.length === 0) {
        await this.taskService.loadData();
        tasks = await firstValueFrom(this.taskService.tasksView$);
      }

      const userId = this.auth.currentUserValue?.id;
      if (!userId) return;

      const userRole = this.auth.getStaffRole() as StaffRole | null;
      const isOwner = this.auth.isOwner();
      const isManager = this.auth.isManager();

      // Filtra le task visibili per l'utente corrente
      const visibleTasks = tasks.filter(task =>
        this.taskService.isTaskVisibleForUser(task, userId, userRole, isOwner || isManager)
      );

      if (visibleTasks.length === 0) {
        console.warn('[Tutorial] Nessuna task visibile trovata per lo step task-detail');
        // Potresti saltare lo step o mostrare un messaggio
        return;
      }

      const firstTask = visibleTasks[0];
      targetRoute = `/restaurant/task-detail/${firstTask.id}`;
    } catch (error) {
      console.error('[Tutorial] Errore nel recupero della task per task-detail', error);
      return;
    }
  }

  const currentUrl = this.router.url.split('?')[0];

  // Se siamo già sulla rotta giusta (confronto semplificato per task-detail)
  if (step.id === 'task-detail' && currentUrl.startsWith('/restaurant/task-detail/')) {
    const currentId = currentUrl.split('/').pop();
    const targetId = targetRoute.split('/').pop();
    if (currentId === targetId) {
      this.recalculate();
      return;
    }
  } else if (currentUrl === targetRoute) {
    this.recalculate();
    return;
  }

  this.navSubscription?.unsubscribe();

  this.navSubscription = this.router.events.pipe(
    filter(e => e instanceof NavigationEnd),
    take(1)
  ).subscribe(() => {
    window.scrollTo(0, 0);
    const delay = step.id === 'task-detail' ? 600 : 150;
    setTimeout(() => this.recalculate(), delay);
  });

  this.router.navigate([targetRoute]);
}


  ngAfterViewInit(): void {
    this.zone.runOutsideAngular(() => {
      this.resizeObserver = new ResizeObserver(() => {
        this.zone.run(() => this.recalculate());
      });
      this.resizeObserver.observe(document.body);

      this.sidebarObserver = new ResizeObserver(() => {
        this.zone.run(() => this.recalculate());
      });
      const sidebar = document.querySelector('.sidebar');
      if (sidebar) {
        this.sidebarObserver.observe(sidebar);
      }

      this._onScroll = () => this.zone.run(() => this._updateHighlightOnly());
      window.addEventListener('scroll', this._onScroll, { passive: true, capture: true });
    });
  }

  private _updateHighlightOnly(): void {
    const tooltipData = this.tutorial.currentTooltipData();
    if (!tooltipData?.tooltipTarget) return;

    const target = document.querySelector(tooltipData.tooltipTarget);
    if (!target) return;

    const rect = target.getBoundingClientRect();
    if (rect.width === 0 || rect.height === 0) return;

    this.highlightRect.set(rect);
    this._computePosition(rect, tooltipData.tooltipPosition);
  }

  ngOnDestroy(): void {
    this.resizeObserver?.disconnect();
    this.sidebarObserver?.disconnect();
    this.navSubscription?.unsubscribe();
    if (this._onScroll) {
      window.removeEventListener('scroll', this._onScroll, { capture: true });
    }
  }

  public recalculate(attempt = 0): void {
    const tooltipData = this.tutorial.currentTooltipData();

    if (!tooltipData?.tooltipTarget) {
      this.tooltipPos.set(null);
      this.highlightRect.set(null);
      return;
    }

    const target = document.querySelector(tooltipData.tooltipTarget);

    if (!target) {
      if (attempt < 5) {
        setTimeout(() => this.recalculate(attempt + 1), 150 * (attempt + 1));
      } else {
        console.warn(`[Tutorial] "${tooltipData.tooltipTarget}" non trovato → fallback`);
        this.tooltipPos.set(null);
        this.highlightRect.set(null);
      }
      return;
    }

    // --- NUOVA LOGICA: apri sidebar su mobile se necessario ---
    const isMobile = window.innerWidth < 768;
    const sidebarClosed = this.auth.getSidebarCollapsed(); // assumiamo che AuthService abbia questo metodo
    const insideSidebar = target.closest('.sidebar') !== null;

    if (isMobile && sidebarClosed && insideSidebar) {
      // Apri la sidebar e riprova dopo un breve delay
      this.auth.setSidebarCollapsed(false);
      setTimeout(() => this.recalculate(attempt + 1), 300);
      return;
    }
    // ---------------------------------------------------------

    const rect = target.getBoundingClientRect();

    if (rect.width === 0 || rect.height === 0) {
      if (attempt < 5) {
        setTimeout(() => this.recalculate(attempt + 1), 150 * (attempt + 1));
      } else {
        this.tooltipPos.set(null);
        this.highlightRect.set(null);
      }
      return;
    }

    target.scrollIntoView({ behavior: 'smooth', block: 'center' });

    setTimeout(() => {
      const updatedRect = target.getBoundingClientRect();
      this.highlightRect.set(updatedRect);
      this._computePosition(updatedRect, tooltipData.tooltipPosition);
    }, 300);
  }

  private _computePosition(rect: DOMRect, preferredPosition?: string): void {
    const isMobile = this.isMobile();
    const SIDEBAR_W = isMobile ? 0 : this.getSidebarWidth();
    const GAP = 16;
    
    // Dimensioni dinamiche per mobile
    const TOOLTIP_W = isMobile ? Math.min(350, window.innerWidth - 32) : 450;
    const TOOLTIP_H = 200; // Altezza stimata (il CSS gestirà l'effettiva altezza)

    const vw = window.innerWidth;
    const vh = window.innerHeight;

    // Gestione sicura del tipo per preferredPosition
    const preferred = (preferredPosition ?? 'bottom') as 'top' | 'bottom' | 'left' | 'right';

    const candidates: Array<{ pos: 'top' | 'bottom' | 'left' | 'right'; top: number; left: number }> = [
      { pos: 'bottom', top: rect.bottom + GAP, left: rect.left + rect.width/2 - TOOLTIP_W/2 },
      { pos: 'top', top: rect.top - TOOLTIP_H - GAP, left: rect.left + rect.width/2 - TOOLTIP_W/2 },
      { pos: 'right', top: rect.top + rect.height/2 - TOOLTIP_H/2, left: rect.right + GAP },
      { pos: 'left', top: rect.top + rect.height/2 - TOOLTIP_H/2, left: rect.left - TOOLTIP_W - GAP }
    ];

    const fitsInViewport = (top: number, left: number): boolean => {
      return (
        left >= SIDEBAR_W + 8 &&
        left + TOOLTIP_W <= vw - 8 &&
        top >= 8 &&
        top + TOOLTIP_H <= vh - 8
      );
    };

    // Ordine di preferenza: prima quello richiesto
    const ordered = [
      candidates.find(c => c.pos === preferred)!,
      ...candidates.filter(c => c.pos !== preferred)
    ];

    const chosen = ordered.find(c => fitsInViewport(c.top, c.left)) ?? ordered[0];

    // Clamp di sicurezza
    const left = Math.max(SIDEBAR_W + 8, Math.min(chosen.left, vw - TOOLTIP_W - 8));
    const top  = Math.max(8, Math.min(chosen.top, vh - TOOLTIP_H - 8));

    this.tooltipPos.set({ top, left, arrowSide: chosen.pos });
  }

  private isMobile(): boolean {
    return window.innerWidth < 768;
  }

  getDots(total: number): number[] {
    return Array.from({ length: total }, (_, i) => i);
  }

  private getSidebarWidth(): number {
    const sidebarEl = document.querySelector('.sidebar');
    if (!sidebarEl) return 0;
    return (sidebarEl as HTMLElement).offsetWidth;
  }
}