// shared/guards/supplierguard.ts
import { Injectable, inject } from '@angular/core';
import { CanActivate, Router } from '@angular/router';
import { AuthService } from './Base/auth.service';

@Injectable({
  providedIn: 'root'
})
export class SupplierGuard implements CanActivate {
  private authService = inject(AuthService);
  private router = inject(Router);

  async canActivate(): Promise<boolean> {
    await this.authService.waitForAuthInit();
    
    if (!this.authService.isAuthenticated()) {
      this.router.navigate(['/login']);
      return false;
    }

    const currentContext = this.authService.getCurrentContext();
    const canBeSupplier = this.authService.canBeSupplier();
    
    console.log('🚚 SupplierGuard Debug:', { 
      currentContext, 
      canBeSupplier,
      availableContexts: this.authService.getAvailableContexts()
    });
    
    // PERMETTI ACCESSO SE:
    // 1. Il contesto corrente è 'supplier'
    // 2. L'utente può essere fornitore (ha record supplier approvato)
    const canAccessSupplierArea = 
      currentContext === 'supplier' ||
      canBeSupplier;

    console.log('🔐 SupplierGuard - Can access supplier area:', canAccessSupplierArea);

    if (canAccessSupplierArea) {
      // Se può accedere ma il contesto non è supplier, impostalo
      if (currentContext !== 'supplier') {
        console.log('🔄 Setting context to supplier for supplier area access');
        this.authService.setContext('supplier');
      }
      return true;
    }

    // Se non può accedere all'area fornitore, reindirizza all'area customer
    console.log('🚫 User cannot access supplier area, redirecting to customer');
    this.authService.setContext('customer');
    this.router.navigate(['/customer/menu-display']);
    return false;
  }
}