// shared/guards/staffguard.ts - VERSIONE SEMPLIFICATA
import { Injectable, inject } from '@angular/core';
import { CanActivate, Router } from '@angular/router';
import { AuthService } from '../../services/Base/auth.service';

@Injectable({
  providedIn: 'root'
})
export class StaffGuard implements CanActivate {
  private authService = inject(AuthService);
  private router = inject(Router);

  async canActivate(): Promise<boolean> {
    await this.authService.waitForAuthInit();
    
    if (!this.authService.isAuthenticated()) {
      this.router.navigate(['/login']);
      return false;
    }

    const currentContext = this.authService.getCurrentContext();
    const canBeStaff = this.authService.canBeStaff();
    
    console.log('👨‍💼 StaffGuard Debug:', { 
      currentContext, 
      canBeStaff,
      staffRole: this.authService.getStaffRole()
    });
    
    const canAccessStaffArea = 
      currentContext === 'staff' ||
      this.authService.isOwner() ||
      canBeStaff;

    if (canAccessStaffArea) {
      if (currentContext !== 'staff') {
        console.log('🔄 Setting context to staff for staff area access');
        this.authService.setContext('staff');
      }
      return true;
    }

    // 🔥 MIGLIORIA: Reindirizza alla dashboard appropriata
    this.redirectToAppropriateDashboard();
    return false;
  }

  private redirectToAppropriateDashboard() {
    const context = this.authService.getCurrentContext();
    switch (context) {
      case 'supplier':
        this.router.navigate(['/supplier/dashboard']);
        break;
      case 'customer':
      default:
        this.router.navigate(['/customer/menu-display']);
        break;
    }
  }
}