// shared/guards/roleguard.ts - VERSIONE CORRETTA
import { Injectable, inject } from '@angular/core';
import { CanActivate, ActivatedRouteSnapshot, Router } from '@angular/router';
import { AuthService } from '../../services/Base/auth.service';
import { PermissionService } from './permission.service';

@Injectable({
  providedIn: 'root'
})
export class RoleGuard implements CanActivate {
  private authService = inject(AuthService);
  private permissionService = inject(PermissionService);
  private router = inject(Router);

async canActivate(route: ActivatedRouteSnapshot): Promise<boolean> {
  console.log('🔐 RoleGuard: Checking route:', route.routeConfig?.path);
  
  await this.authService.waitForAuthInit();
  
  const user = this.authService.currentUserValue;
  if (!user) {
    this.router.navigate(['/login']);
    return false;
  }

  // Se l'utente non ha alcun permesso, reindirizza a no-permission (ma evita loop)
  if (this.authService.isRestaurantUser() && !this.authService.hasAnyPermissions()) {
    // Se stiamo già sulla rotta no-permission, permetti l'accesso
    if (route.routeConfig?.path === 'no-permission') {
      console.log('🔐 RoleGuard - Already on no-permission, allowing access');
      return true;
    }
    console.log('🔐 RoleGuard - User has no permissions, redirecting to no-permission');
    this.router.navigate(['/no-permission']);
    return false;
  }

  const requiredPermissions = route.data['permissions'] as string[];
  
  if (!requiredPermissions || requiredPermissions.length === 0) {
    console.log('🔐 RoleGuard - No permissions required, access granted');
    return true;
  }

  const hasPermission = this.permissionService.hasAnyPermission(requiredPermissions);
  
  if (!hasPermission) {
    console.log('🔐 Permission denied, redirecting to dashboard');
    this.redirectToAppropriateDashboard();
    return false;
  }

  console.log('🔐 RoleGuard - Access granted');
  return true;
}

  private redirectToAppropriateDashboard() {
    const context = this.authService.getCurrentContext();
    switch (context) {
      case 'staff':
        this.router.navigate(['/restaurant/dashboard']);
        break;
      case 'supplier':
        this.router.navigate(['/supplier/dashboard']);
        break;
      case 'customer':
      default:
        this.router.navigate(['/customer']);
        break;
    }
  }
}