import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router } from '@angular/router';
import { AuthService } from '../../services/Base/auth.service';
import { LoadingService } from '../../services/Base/loading.service';
import { ThemeService } from '../../services/Base/theme.service';

@Component({
  selector: 'app-footer',
  standalone: true,
  imports: [CommonModule],
  template: `
    <!-- Nascondi footer durante loading -->
    <footer *ngIf="!(loadingService.loading$ | async)" 
            class="app-footer" 
            [class.app-footer--compact]="isCompactMode()">
      
      <!-- Footer Completo (landing, login, etc) -->
      <div class="footer-full" *ngIf="!isCompactMode()">
        <div class="flex flex-col gap-lg p-lg" >
          
          <!-- Sezione superiore -->
          <div class="flex flex-wrap justify-between gap-lg">
            
            <!-- Brand -->
            <div class="flex flex-col gap-md" style="flex: 1;">
              <div class="flex items-center gap-sm">
              <img 
                *ngIf="(themeService.currentTheme$ | async) === 'light'" 
                src="logo_promethea_dark.webp" 
                alt="Promethea" 
                class="logopiccolo">
              <img 
                *ngIf="(themeService.currentTheme$ | async) === 'dark'" 
                src="logo_promethea_light.webp" 
                alt="Promethea" 
                class="logopiccolo">
              </div>
              <p class="text-muted text-sm">
                Gestione aziendale a 360° per ristoranti. <br>
                Ottimizzazione, digitalizzazione e crescita.
              </p>
              <p class="text-mini font-semibold gradient-text">makin' life easier</p>
            </div>

            <!-- Link Prodotto -->
            <div class="flex flex-col gap-sm" style="flex: 0 0 150px;">
              <h4 class="font-bold text-sm mb-sm">Prodotto</h4>
              <a href="#/features" class="link text-sm">Funzionalità</a>
              <a href="/prezzi" class="link text-sm" style="display:none;">Prezzi</a>
              <a href="/demo" class="link text-sm" style="display:none;">Richiedi Demo</a>
            </div>

            <!-- Link Risorse -->
            <div class="flex flex-col gap-sm" style="flex: 0 0 150px;display:none;">
              <h4 class="font-bold text-sm mb-sm">Risorse</h4>
              <a href="/blog" class="link text-sm">Blog</a>
              <a href="/supporto" class="link text-sm">Supporto</a>
              <a href="/api-docs" class="link text-sm">API Docs</a>
            </div>

            <!-- Contatti -->
            <div class="flex flex-col gap-sm" style="flex: 0 0 200px;">
              <h4 class="font-bold text-sm mb-sm">Contatti</h4>
              <div class="flex gap-sm items-start">
                <span class="material-icons text-sm">location_on</span>
                <span class="text-sm">Via della Ginnastica 21/A<br>34126 Trieste (TS)</span>
              </div>
              <div class="flex gap-sm items-center">
                <span class="material-icons text-sm">phone</span>
                <a href="tel:+39040993210" class="link text-sm">040 993210</a>
              </div>
              <div class="flex gap-sm items-center">
                <span class="material-icons text-sm">email</span>
                <a href="mailto:info@prometheasrl.it" class="link text-sm">info&#64;prometheasrl.it</a>
              </div>
            </div>
          </div>

          <!-- Divider -->
          <div style="border-top: 1px solid var(--smoke-1);"></div>

          <!-- Bottom -->
          <div class="flex flex-wrap justify-between items-center gap-md">
            <div class="flex flex-wrap gap-md items-center text-mini text-muted">
              <span>© 2026 Promethea S.r.l.</span>
              <span>P.IVA 01417350327</span>
              <a href="/policy" class="link text-mini">Privacy</a>
              <a href="/termini" 
              style="display: none;"
              class="link text-mini">Termini</a>
            </div>
          </div>
        </div>
      </div>

      <!-- Footer Compatto (dashboard) -->
      <div class="footer-compact" *ngIf="isCompactMode()">
        <div class="flex flex-wrap justify-between items-center gap-md p-md">
          
          <div class="flex items-center gap-md text-mini text-muted">
            <div class="flex items-center gap-sm">
              <a href="https://www.prometheasrl.it/" target="_blank" rel="noopener noreferrer">
                <img 
                  *ngIf="(themeService.currentTheme$ | async) === 'light'" 
                  src="logo_promethea_dark.webp" 
                  alt="Promethea" 
                  class="logomini">
                <img 
                  *ngIf="(themeService.currentTheme$ | async) === 'dark'" 
                  src="logo_promethea_light.webp" 
                  alt="Promethea" 
                  class="logomini">
              </a>
            </div>
            <span>© 2026</span>
            <a href="#/policy" style="display: none;" class="link text-mini">Privacy</a>
            <a href="termini" class="link text-mini"
            style="display: none;">Termini</a>
          </div>

          <div class="flex items-center gap-md text-mini text-muted">
            <a href="/supporto" class="link text-mini flex items-center gap-sm"
            style="display: none;">
              <span class="material-icons">help_outline</span>
              Supporto
            </a>
            <a href="mailto:info@prometheasrl.it" class="link text-mini flex items-center gap-sm">
              <span class="material-icons">email</span>
              Contattaci
            </a>
          </div>
        </div>
      </div>
    </footer>
  `,
  styles: [`
    .app-footer {
      margin-top: auto;
      border-top: 1px solid var(--smoke-1);
      background: var(--background);
    }

    .app-footer--compact .footer-full {
      display: none;
    }

    .app-footer:not(.app-footer--compact) .footer-compact {
      display: none;
    }

    @media (max-width: 768px) {
      .footer-full .flex.flex-wrap {
        flex-direction: column;
      }
    }
  `]
})
export class Footer {
  private router = inject(Router);
  private authService = inject(AuthService);
  protected loadingService = inject(LoadingService);
  protected themeService = inject(ThemeService);
  
  isCompactMode(): boolean {
    const currentUrl = this.router.url;
    
    // Footer COMPLETO solo per queste pagine specifiche
    const fullFooterPages = [
      '/login',
      '/register', 
      '/policy'
    ];
    
    // Se sei in una di queste pagine → Footer COMPLETO
    return !fullFooterPages.some(page => currentUrl.startsWith(page));
  }
}