// context-selector.component.ts
import { Component, Input, inject, OnInit, OnDestroy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AuthService } from '../../services/Base/auth.service';
import { Router } from '@angular/router';
import { Subscription, combineLatest } from 'rxjs';
import { TutorialService } from '../../services/tutorial.service';

@Component({
  selector: 'app-context-selector',
  standalone: true,
  imports: [CommonModule, FormsModule],
  template: `
    <ng-container *ngIf="isReady">
      <div class="context-selector" 
           *ngIf="availableContexts.length > 1"
           [class.text-large]="largeText">
        <label class="context-visualizzazione">Visualizzazione:</label>
        <select 
          class="tipovisualizzazione p-mini"
          [(ngModel)]="selectedContext"
          (ngModelChange)="onContextChange($event)"
          [title]="getContextTitle(selectedContext)">
          <option *ngFor="let context of availableContexts" [value]="context">
            {{ getContextLabel(context) }}
          </option>
        </select>
      </div>
    </ng-container>
  `,
  styleUrls: ['./context-selector.css']
})
export class ContextSelector implements OnInit, OnDestroy {
  protected authService = inject(AuthService);
  private router = inject(Router);
  private tutorialService = inject(TutorialService);

  @Input() largeText: boolean = false;

  isReady = false;
  availableContexts: Array<'customer' | 'staff' | 'supplier'> = [];
  selectedContext: 'customer' | 'staff' | 'supplier' = 'customer';

  private subscriptions: Subscription[] = [];

  async ngOnInit() {
    // Attendi che l'AuthService abbia completato l'inizializzazione
    await this.authService.waitForAuthInit();

    // Combina restaurants e supplier per aggiornare availableContexts
    this.subscriptions.push(
      combineLatest([
        this.authService.availableRestaurants$,
        this.authService.supplier$
      ]).subscribe(([restaurants, supplier]) => {
        const contexts: Array<'customer' | 'staff' | 'supplier'> = ['customer'];
        if (restaurants && restaurants.length > 0) contexts.push('staff');
        if (supplier) contexts.push('supplier');
        this.availableContexts = contexts;
      })
    );

    // Sottoscrizione al contesto corrente
    this.subscriptions.push(
      this.authService.currentContext$.subscribe(context => {
        this.selectedContext = context;
      })
    );

    this.isReady = true;
  }

  onContextChange(newContext: 'customer' | 'staff' | 'supplier') {
    this.switchContext(newContext);
  }

async switchContext(newContext: 'customer' | 'staff' | 'supplier') {
  const success = await this.authService.switchContext(newContext);
  if (success) {
    switch (newContext) {
      case 'staff':
        this.router.navigate(['/restaurant/dashboard']);
        break;
      case 'supplier':
        this.router.navigate(['/supplier/dashboard']);
        break;
      case 'customer':
        this.router.navigate(['/customer/menu-display']);
        break;
    }

    // Dopo il cambio contesto, controlla se c'è un tutorial da mostrare
    // (es. utente passa da customer → staff per la prima volta)
    await this.tutorialService.checkAndStart();
  }
}


  getContextLabel(context: string): string {
    const labels: Record<string, string> = {
      customer: 'Cliente',
      staff: 'Ristorante',
      supplier: 'Fornitore'
    };
    return labels[context] || context;
  }

  getContextTitle(context: string): string {
    return `Visualizza come ${this.getContextLabel(context).toLowerCase()}`;
  }

  ngOnDestroy() {
    this.subscriptions.forEach(sub => sub.unsubscribe());
  }
}