// app.ts
import {
  Component,
  HostListener,
  inject,
  OnInit,
  OnDestroy,
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  effect,
} from '@angular/core';
import { CommonModule, AsyncPipe } from '@angular/common';
import {
  ActivatedRoute,
  NavigationEnd,
  Router,
  RouterModule,
  RouterOutlet,
} from '@angular/router';
import { BehaviorSubject, Observable, Subscription, combineLatest } from 'rxjs';
import {
  filter,
  map,
  startWith,
  distinctUntilChanged,
  tap,
  switchMap,
} from 'rxjs/operators';

import { AuthService } from './services/Base/auth.service';
import { SupplierAuthService, SupplierProfile } from './services/supplier-auth.service';
import { User, Restaurant } from './models';
import { Loader } from './shared/loader/loader';
import { LoadingService } from './services/Base/loading.service';
import { ContextSelector } from './shared/context-selector/context-selector';
import { Theme, ThemeService } from './services/Base/theme.service';
import { LucideAngularModule } from 'lucide-angular';
import { Header } from './shared/header/header';
import { BreakpointObserver, Breakpoints } from '@angular/cdk/layout';
import { Footer } from './shared/footer/footer';
import { TutorialModal } from './shared/tutorial/tutorial';
import { TutorialTooltip } from './shared/tutorial-tooltip/tutorial-tooltip';
import { TutorialService } from './services/tutorial.service';
import { ChatService } from './services/chat.service';
import { TaskService } from './services/task.service';

@Component({
  selector: 'app-root',
  standalone: true,
  // ChangeDetectionStrategy.OnPush: il componente si aggiorna SOLO quando
  // un Input cambia o un Observable emette via async pipe.
  // Questo elimina alla radice il problema NG0100 perché Angular non fa più
  // il doppio-check sui metodi chiamati nel template.
  changeDetection: ChangeDetectionStrategy.OnPush,
  imports: [
    CommonModule,
    AsyncPipe,
    RouterOutlet,
    RouterModule,
    Loader,
    ContextSelector,
    LucideAngularModule,
    Header,
    Footer,
    TutorialModal,
    TutorialTooltip,
  ],
  templateUrl: './app.html',
  styleUrls: ['./app.css'],
})
export class App implements OnInit, OnDestroy {
  public authService = inject(AuthService);
  private supplierAuthService = inject(SupplierAuthService);
  private loadingService = inject(LoadingService);
  public themeService = inject(ThemeService);
  public tutorialService = inject(TutorialService);
  private chatService = inject(ChatService);
  private taskService = inject(TaskService);
  private breakpointObserver = inject(BreakpointObserver);
  private activatedRoute = inject(ActivatedRoute);
  private router = inject(Router);
  private cdr = inject(ChangeDetectorRef);

  // ── Stato sidebar ─────────────────────────────────────────────────────────
  isSidebarCollapsed = true;
  private previousSidebarState: boolean | null = null;

  // ── Stato locale (non-observable, usati solo da metodi TS) ────────────────
  currentUser: User | null = null;
  currentRestaurant: Restaurant | null = null;
  supplierProfile: SupplierProfile | null = null;
  loading = false;
  isLargeText = false;

  // ── Observables esposti al template (tutti via async pipe) ────────────────

  /** Autenticazione: UNICA sorgente di verità per *ngIf="isAuthenticated$ | async" */
  isAuthenticated$: Observable<boolean> = this.authService.currentUser$.pipe(
    map(user => !!user)
  );

  /** Contesto corrente come observable */
  isRestaurantUser$: Observable<boolean> = this.authService.currentContext$.pipe(
    map(ctx => ctx === 'staff')
  );

  isCustomerUser$: Observable<boolean> = this.authService.currentContext$.pipe(
    map(ctx => ctx === 'customer')
  );

  isSupplierUser$: Observable<boolean> = this.authService.currentContext$.pipe(
    map(ctx => ctx === 'supplier')
  );

  /** Mostra il context selector solo se ci sono più contesti disponibili */
  shouldShowContextSelector$: Observable<boolean> = combineLatest([
    this.authService.currentContext$,
    this.authService.availableRestaurants$,
    this.authService.supplier$,
  ]).pipe(
    map(() => this.authService.getAvailableContexts().length > 1)
  );

  /** Unread chat */
  totalUnread$ = this.chatService.totalUnread$;

  /** Header: titolo e icona dalla route */
  pageTitle$!: Observable<string>;
  pageIcon$!: Observable<string>;

  /** Mobile */
  isMobile$!: Observable<boolean>;
  showMobileToggle$!: Observable<boolean>;

  /** Nasconde header globale su certe route */
  hideGlobalHeader$!: Observable<boolean>;

  // ── Subscriptions (solo per side-effects, NON per alimentare il template) ──
  private subs = new Subscription();

  constructor() {
    this.initHeaderObservables();

    this.hideGlobalHeader$ = this.router.events.pipe(
      filter(event => event instanceof NavigationEnd),
      startWith(null),
      map(() => {
        let route = this.activatedRoute;
        while (route.firstChild) route = route.firstChild;
        return route.snapshot.data['hideGlobalHeader'] === true;
      })
    );

    // Effect per gestire sidebar durante il tutorial
    effect(() => {
      const tutorialVisible = this.tutorialService.isVisible();
      if (tutorialVisible && this.previousSidebarState === null) {
        this.previousSidebarState = this.authService.getSidebarCollapsed();
        if (!this.previousSidebarState) {
          this.authService.setSidebarCollapsed(true);
        }
      } else if (!tutorialVisible && this.previousSidebarState !== null) {
        const current = this.authService.getSidebarCollapsed();
        if (current !== this.previousSidebarState) {
          this.authService.setSidebarCollapsed(this.previousSidebarState);
        }
        this.previousSidebarState = null;
      }
    });
  }

  async ngOnInit() {
    // Tema
    this.themeService.initializeTheme();

    // Loader globale
    this.subs.add(
      this.loadingService.loading$.subscribe(isLoading => {
        this.loading = isLoading;
        this.cdr.markForCheck();
      })
    );

    // Sidebar collapsed
    this.subs.add(
      this.authService.sidebarCollapsed$.subscribe(collapsed => {
        this.isSidebarCollapsed = collapsed;
        this.cdr.markForCheck();
      })
    );

    // Utente corrente (side-effects: permessi, tutorial, debug)
    this.subs.add(
      this.authService.currentUser$.subscribe(user => {
        this.currentUser = user;
        if (user) {
          this.authService.loadPermissions();
          this.tutorialService.checkAndStart();
          this.printDebugInfo();
        } else {
          this.currentRestaurant = null;
          this.supplierProfile = null;
        }
        this.cdr.markForCheck();
      })
    );

    // Ristorante corrente
    this.subs.add(
      this.authService.currentRestaurant$.subscribe(restaurant => {
        this.currentRestaurant = restaurant;
        if (restaurant) {
          this.chatService.loadConversations();
        }
        this.cdr.markForCheck();
      })
    );

    // Profilo fornitore
    this.subs.add(
      this.supplierAuthService.supplierProfile$.subscribe(profile => {
        this.supplierProfile = profile;
        this.cdr.markForCheck();
      })
    );
  }

  ngOnDestroy() {
    this.subs.unsubscribe();
  }

  // ── Header observables ────────────────────────────────────────────────────

  private initHeaderObservables() {
    const routeData$ = this.router.events.pipe(
      filter(event => event instanceof NavigationEnd),
      startWith(null),
      map(() => {
        let route = this.activatedRoute;
        while (route.firstChild) route = route.firstChild;
        return route.snapshot.data;
      }),
      distinctUntilChanged((prev, curr) => prev['title'] === curr['title'])
    );

    this.pageTitle$ = routeData$.pipe(map(data => data['title'] || 'Platea'));
    this.pageIcon$ = routeData$.pipe(map(data => data['icon'] || 'layout-dashboard'));

    this.isMobile$ = this.breakpointObserver
      .observe([Breakpoints.Handset, Breakpoints.TabletPortrait])
      .pipe(map(result => result.matches));

    this.showMobileToggle$ = combineLatest([
      this.isMobile$,
      this.authService.sidebarCollapsed$,
    ]).pipe(map(([isMobile, isCollapsed]) => isMobile && isCollapsed));
  }

  // ── Metodi usati nel template (solo quelli che NON fanno da guard su ngIf) ──

  getUserDisplayName(): string {
    const user = this.currentUser;
    if (!user) return '';
    const firstName = user.first_name || '';
    const lastName = user.last_name || '';
    if (firstName && lastName) return `${firstName} ${lastName}`;
    if (firstName) return firstName;
    if (lastName) return lastName;
    return user.email || 'Utente';
  }

  getUserInitial(): string {
    const user = this.currentUser;
    if (!user) return '';
    const firstName = user.first_name || '';
    const lastName = user.last_name || '';
    if (firstName && lastName) return `${firstName.charAt(0)}${lastName.charAt(0)}`.toUpperCase();
    if (firstName) return firstName.charAt(0).toUpperCase();
    if (lastName) return lastName.charAt(0).toUpperCase();
    return user.email?.charAt(0).toUpperCase() || 'U';
  }

  getRestaurantName(): string {
    return this.currentRestaurant?.name || 'Ristorante';
  }

  getSupplierCompanyName(): string {
    return this.supplierProfile?.company_name || 'Fornitore';
  }

  getRoleIcon(): string {
    const ctx = this.authService.getCurrentContext();
    if (ctx === 'staff') return 'store';
    if (ctx === 'supplier') return 'truck';
    return 'user';
  }

  getRoleClass(): string {
    const role = this.authService.getStaffRole() || 'guest';
    return `role-${role}`;
  }

  getRoleLabel(): string {
    const role = this.authService.getStaffRole() || 'guest';
    const map: Record<string, string> = {
      owner: 'admin_panel_settings',
      manager: 'supervisor_account',
      chef: 'restaurant',
      waiter: 'room_service',
      kitchen_staff: 'kitchen',
    };
    return map[role] || 'person';
  }

  getRoleDisplayName(): string {
    const role = this.authService.getStaffRole() || 'guest';
    const map: Record<string, string> = {
      owner: 'Proprietario',
      manager: 'Responsabile',
      chef: 'Chef',
      waiter: 'Cameriere',
      kitchen_staff: 'Staff Cucina',
      guest: 'Ospite',
    };
    return map[role] || role;
  }

  get iconSize(): number {
    const base = this.isSidebarCollapsed ? 32 : 24;
    return this.isLargeText ? Math.round(base * 1.5) : base;
  }

  getSettingsRoute(): string {
    const ctx = this.authService.getCurrentContext();
    if (ctx === 'staff' && this.authService.hasPermission('manage_restaurant_settings')) {
      return '/restaurant/settings';
    }
    if (ctx === 'supplier') return '/supplier/settings';
    return '/customer';
  }

  // ── Azioni ────────────────────────────────────────────────────────────────

  async logout() {
    await this.authService.logout();
    this.authService.setSidebarCollapsed(true);
  }

  toggleSidebar() {
    if (this.tutorialService.isVisible()) return;
    this.authService.toggleSidebar();
  }

  toggleSize(): void {
    if (this.tutorialService.isVisible()) return;
    this.isLargeText = !this.isLargeText;
  }

  onSidebarNavClick(event: Event) {
    if (window.innerWidth > 768) return;
    const target = event.target as HTMLElement;
    if (target.closest('.nav-link')) {
      this.authService.setSidebarCollapsed(true);
    }
  }

  navigateBasedOnRole() {
    const ctx = this.authService.getCurrentContext();
    if (ctx === 'staff') this.router.navigate(['/restaurant/dashboard']);
    else if (ctx === 'supplier') this.router.navigate(['/supplier/dashboard']);
    else if (ctx === 'customer') this.router.navigate(['/customer']);
    else this.router.navigate(['/login']);
  }

  setTheme(theme: Theme) {
    this.themeService.setTheme(theme);
  }

  @HostListener('document:click', ['$event'])
  onDocumentClick(event: Event) {
    if (window.innerWidth > 768) return;
    const target = event.target as HTMLElement;
    if (
      target.closest('.mobile-sidebar-toggle') ||
      target.closest('.mobile-toggle')
    ) return;
    if (!this.isSidebarCollapsed) {
      if (!target.closest('.sidebar') && !target.closest('.sidebar-toggle')) {
        this.authService.setSidebarCollapsed(true);
      }
    }
  }

  // ── Debug ─────────────────────────────────────────────────────────────────

  private printDebugInfo() {
    console.log('🔍 DEBUG - App Component State:');
    console.log('  - Current Context:', this.authService.getCurrentContext());
    console.log('  - Current Staff:', this.authService.getCurrentStaff());
    console.log('  - Current Restaurant:', this.currentRestaurant);
    console.log('  - Available Contexts:', this.authService.getAvailableContexts());
    console.log('  - Can Be Staff:', this.authService.canBeStaff());
    console.log('  - Is Owner:', this.authService.isOwner());
    console.log('  - User Role:', this.authService.getUserRole());
  }
}