import { Routes } from '@angular/router';
import { RoleGuard } from './shared/guards/roleguard';
import { StaffGuard } from './shared/guards/staffguard';
import { SupplierGuard } from './services/supplierguard';
import { AuthGuard } from './shared/guards/authguard';

export const routes: Routes = [

  // ── PUBBLICHE ──────────────────────────────────────────────────
  {
    path: 'login',
    loadComponent: () => import('./auth/login/login').then(m => m.Login)
  },
  {
    path: 'policy',
    loadComponent: () => import('./auth/policy/policy').then(m => m.Policy),
    data: { title: 'Privacy Policy', icon: 'file-text' }
  },
  {
    path: 'features',
    loadComponent: () => import('./shared/features/features').then(m => m.Features),
    data: { hideGlobalHeader: true }
  },
  {
    path: 'register',
    children: [
      {
        path: '',
        loadComponent: () => import('./auth/register/register').then(m => m.Register),
        data: { hideGlobalHeader: true }
      },
      {
        path: ':role',
        loadComponent: () => import('./auth/register/register').then(m => m.Register),
        data: { hideGlobalHeader: true }
      }
    ]
  },

  // ── PUBBLICHE CUSTOMER (senza auth) ───────────────────────────
  {
    path: 'customer/restaurant/restaurant-list',
    loadComponent: () => import('./customer/restaurant/restaurant-list/restaurant-list')
      .then(m => m.RestaurantList),
    data: { title: 'Cerca Ristoranti', icon: 'utensils' }
  },
  {
    path: 'customer/restaurant/:restaurantId/map',
    loadComponent: () => import('./customer/restaurant/restaurant-map-viewer/restaurant-map-viewer')
      .then(m => m.RestaurantMapViewer),
    data: { hideGlobalHeader: true }
  },

  // ── RISTORANTE ─────────────────────────────────────────────────
  {
    path: 'restaurant',
    canActivate: [AuthGuard, StaffGuard],
    children: [
      {
        path: 'dashboard',
        loadComponent: () => import('./restaurant/dashboard/dashboard').then(m => m.Dashboard),
        canActivate: [RoleGuard],
        data: { permissions: ['view_dashboard'], title: 'Dashboard', icon: 'layout-dashboard' }
      },
      {
        path: 'menu',
        loadComponent: () => import('./restaurant/menu/menu-builder/menu-builder').then(m => m.MenuBuilder),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_menu', 'view_menu_readonly', 'manage_dish_photos'], title: 'Menù & Piatti', icon: 'utensils' }
      },
      {
        path: 'menu-pdf-upload',
        loadComponent: () => import('./restaurant/menu/menu-pdf-upload/menu-pdf-upload.component')
          .then(m => m.MenuPdfUploadComponent),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_menu', 'view_menu_readonly', 'manage_dish_photos'], title: 'Menù PDF Upload', icon: 'file-upload' }
      },
      {
        path: 'menu-pdf-zone-editor',
        loadComponent: () => import('./restaurant/menu/pdf-zone-editor/pdf-zone-editor.component')
          .then(m => m.MenuPdfZoneEditorComponent),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_menu', 'view_menu_readonly', 'manage_dish_photos'], title: 'Menù PDF Editor', icon: 'file-upload' }
      },
      {
        path: 'alcoholic-beverages',
        loadComponent: () => import('./restaurant/menu/alcoholic-beverages/alcoholic-beverages')
          .then(m => m.AlcoholicBeverages),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_menu', 'view_menu_readonly', 'manage_dish_photos'], title: 'Bevande', icon: 'glass-water' }
      },
      {
        path: 'orders',
        loadComponent: () => import('./restaurant/orders/live-orders/live-orders').then(m => m.LiveOrders),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_orders'], title: 'Ordini', icon: 'shopping-cart' }
      },
      {
        path: 'kitchen-display',
        loadComponent: () => import('./restaurant/orders/kitchen-display/kitchen-display')
          .then(m => m.KitchenDisplay),
        canActivate: [RoleGuard],
        data: { permissions: ['view_kitchen_display'], title: 'Pannello Cucina', icon: 'chef-hat' }
      },
      {
        path: 'recipe',
        loadComponent: () => import('./restaurant/recipe/recipe').then(m => m.Recipe),
        canActivate: [RoleGuard],
        data: { permissions: ['view_ingredients'], title: 'Ricette', icon: 'scroll-text' }
      },
      {
        path: 'expense-management',
        loadComponent: () => import('./restaurant/expense-management/expense-management')
          .then(m => m.ExpenseManagement),
        canActivate: [RoleGuard],
        data: { permissions: ['view_reports'], title: 'Gestione Spese', icon: 'credit-card' }
      },
      {
        path: 'financial-report',
        loadComponent: () => import('./restaurant/financial/financial-report/financial-report')
          .then(m => m.FinancialReport),
        canActivate: [RoleGuard],
        data: { permissions: ['view_reports'], title: 'Report Finanziario', icon: 'bar-chart-3' }
      },
      {
        path: 'reservation-manager',
        loadComponent: () => import('./restaurant/reservation/reservation-manager/reservation-manager')
          .then(m => m.ReservationManager),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_reservations'], title: 'Lista Prenotazioni', icon: 'notebook-text' }
      },
      {
        path: 'table-map',
        loadComponent: () => import('./restaurant/layout/table-map/table-map').then(m => m.TableMap),
        canActivate: [RoleGuard],
        data: { permissions: ['take_orders'], title: 'Ordini', icon: 'utensils-crossed' }
      },
      {
        path: 'floor-plan',
        loadComponent: () => import('./restaurant/layout/floor-plan/floor-plan').then(m => m.FloorPlanEditor),
        canActivate: [RoleGuard],
        data: { permissions: ['view_table_map'], title: 'Mappa Ristorante', icon: 'table-2' }
      },
      {
        path: 'calendar-view',
        loadComponent: () => import('./restaurant/reservation/calendar-view/calendar-view')
          .then(m => m.RestaurantCalendar),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_reservations', 'view_calendar_readonly'], title: 'Calendario', icon: 'calendar' }
      },
      {
        path: 'inventory',
        loadComponent: () => import('./restaurant/inventory/inventory').then(m => m.Inventory),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_inventory'], title: 'Inventario', icon: 'package' }
      },
      {
        path: 'ingredient-search',
        loadComponent: () => import('./restaurant/ingredient-search/ingredient-search')
          .then(m => m.IngredientSearch),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_inventory'], title: 'Ricerca Ingredienti', icon: 'package-search' }
      },
      {
        path: 'suppliers',
        loadComponent: () => import('./restaurant/suppliers/supplier-manager/supplier-manager')
          .then(m => m.SupplierManager),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_inventory'], title: 'Fornitori', icon: 'truck' }
      },
      {
        path: 'tables',
        loadComponent: () => import('./shared/ui/tablemap-view/tablemap-view').then(m => m.TablemapView),
        canActivate: [RoleGuard],
        data: { permissions: ['take_orders'], title: 'Tavoli', icon: 'table-2' }
      },
      {
        path: 'task-list',
        loadComponent: () => import('./restaurant/tasks/task-list/task-list.component')
          .then(m => m.TaskListComponent),
        canActivate: [RoleGuard],
        data: { title: 'Task', icon: 'clipboard-list' }
      },
      {
        path: 'task-detail/:id',
        loadComponent: () => import('./restaurant/tasks/task-detail/task-detail.component')
          .then(m => m.TaskDetailComponent),
        canActivate: [RoleGuard],
        data: { title: 'Dettaglio Task', icon: 'clipboard-list' }
      },
      {
        path: 'staff-management',
        loadComponent: () => import('./restaurant/staff-management/staff-management')
          .then(m => m.StaffManagement),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_staff'], title: 'Staff', icon: 'users' }
      },
      {
        path: 'marketing-management',
        loadComponent: () => import('./restaurant/marketing-management/marketing-management')
          .then(m => m.MarketingManagement),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_staff', 'manage_marketing'], title: 'Gestione Marketing', icon: 'megaphone' }
      },
      {
        path: 'web-site',
        loadComponent: () => import('./restaurant/web-site/web-site').then(m => m.WebSite),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_staff'], title: 'Crea il tuo sito web', icon: 'globe' }
      },
      {
        path: 'marketing',
        loadComponent: () => import('./restaurant/marketing/marketing').then(m => m.Marketing),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_staff'], title: 'Promuovi il ristorante', icon: 'trending-up' }
      },
      {
        path: 'contabile-fiscale',
        loadComponent: () => import('./restaurant/contabile-fiscale/contabile-fiscale')
          .then(m => m.ContabileFiscale),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_staff'], title: 'Gestione Fiscale', icon: 'landmark' }
      },
      {
        path: 'profile',
        loadComponent: () => import('./restaurant/profile/profile').then(m => m.Profile),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_staff', 'view_profile'], title: 'Profilo', icon: 'user' }
      },
      {
        path: 'settings',
        loadComponent: () => import('./restaurant/settings/restaurant-settings/restaurant-settings')
          .then(m => m.RestaurantSettings),
        canActivate: [RoleGuard],
        data: { permissions: ['manage_restaurant_settings', 'manage_dish_photos'], title: 'Impostazioni', icon: 'settings' }
      },
      {
        path: 'chat-window',
        loadComponent: () => import('./restaurant/chat-window/chat-window').then(m => m.ChatWindow),
        canActivate: [RoleGuard],
        data: { title: 'Chat', icon: 'messages-square' }
      },
      {
        path: 'no-permission',
        loadComponent: () => import('./restaurant/staff-management/no-permission/no-permission')
          .then(m => m.NoPermission),
        data: { title: 'Accesso Negato', icon: 'shield-alert' }
      },
      {
        path: 'timbrature',
        children: [
          {
            path: 'home',
            loadComponent: () => import('./timbrature/features/home/home.component').then(m => m.HomeComponent),
            data: { title: 'Timbrature', icon: 'clock' }
          },
          {
            path: 'lista',
            loadComponent: () => import('./timbrature/features/lista-timbrature/lista-timbrature.component').then(m => m.ListaTimbratureComponent),
            data: { title: 'Lista Timbrature', icon: 'clock' }
          },
          {
            path: 'crea',
            loadComponent: () => import('./timbrature/features/crea-timbratura/crea-timbratura.component').then(m => m.CreaTimbraturaComponent),
            data: { title: 'Nuova Timbratura', icon: 'plus-circle' }
          },
          {
            path: 'crea/:id',
            loadComponent: () => import('./timbrature/features/crea-timbratura/crea-timbratura.component').then(m => m.CreaTimbraturaComponent),
            data: { title: 'Modifica Timbratura', icon: 'pencil' }
          },
          {
            path: 'calendario',
            loadComponent: () => import('./timbrature/features/calendario/calendario.component').then(m => m.CalendarioComponent),
            data: { title: 'Calendario', icon: 'calendar' }
          },
          {
            path: 'dipendenti',
            loadComponent: () => import('./timbrature/features/lista-dipendenti/lista-dipendenti.component').then(m => m.ListaDipendentiComponent),
            data: { title: 'Dipendenti', icon: 'users' }
          },
          {
            path: 'dipendenti/:id',
            loadComponent: () => import('./timbrature/features/dipendente-dettaglio/dipendente-dettaglio.component').then(m => m.DipendenteDettaglioComponent),
            data: { title: 'Dettaglio Dipendente', icon: 'user' }
          },
          {
            path: 'inviti',
            loadComponent: () => import('./timbrature/features/inviti-dipendenti/inviti-dipendenti.component').then(m => m.InvitiDipendentiComponent),
            data: { title: 'Inviti Dipendenti', icon: 'mail' }
          },
          {
            path: 'buste-paga',
            loadComponent: () => import('./timbrature/features/buste-paga/buste-paga.component').then(m => m.BustePagaComponent),
            data: { title: 'Buste Paga', icon: 'file-text' }
          },
          {
            path: 'report',
            loadComponent: () => import('./timbrature/features/report/report.component').then(m => m.ReportComponent),
            data: { title: 'Report', icon: 'bar-chart-3' }
          },
          {
            path: 'turni',
            loadComponent: () => import('./timbrature/features/shift-management/shift-management.component').then(m => m.ShiftManagementComponent),
            data: { title: 'Gestione Turni', icon: 'clipboard-list' }
          },
          {
            path: 'kpi',
            loadComponent: () => import('./timbrature/features/kpi/kpi.component').then(m => m.KpiComponent),
            data: { title: 'KPI', icon: 'activity' }
          },
          {
            path: 'profilo',
            loadComponent: () => import('./timbrature/features/profilo-aziendale/profilo-aziendale.component').then(m => m.ProfiloAziendaleComponent),
            data: { title: 'Profilo Aziendale', icon: 'building' }
          },
          {
            path: 'impostazioni',
            loadComponent: () => import('./timbrature/features/impostazioni/impostazioni.component').then(m => m.ImpostazioniComponent),
            data: { title: 'Impostazioni Timbrature', icon: 'settings' }
          },
          { path: '', redirectTo: 'home', pathMatch: 'full' }
        ]
      },
      { path: '', redirectTo: 'dashboard', pathMatch: 'full' }
    ]
  },

  // ── FORNITORE ──────────────────────────────────────────────────
  {
    path: 'supplier',
    canActivate: [AuthGuard, SupplierGuard],
    data: { roles: ['supplier'], context: 'supplier' },
    children: [
      {
        path: 'dashboard',
        loadComponent: () => import('./supplier/dashboard/supplier-dashboard/supplier-dashboard')
          .then(m => m.SupplierDashboard),
        data: { title: 'Dashboard', icon: 'layout-dashboard' }
      },
      {
        path: 'settings',
        loadComponent: () => import('./supplier/settings/supplier-settings/supplier-settings')
          .then(m => m.SupplierSettings),
        data: { title: 'Impostazioni Fornitore', icon: 'settings' }
      },
      {
        path: 'restaurants',
        loadComponent: () => import('./supplier/restaurants/supplier-restaurants/supplier-restaurants')
          .then(m => m.SupplierRestaurants),
        data: { title: 'Cerca Ristoranti', icon: 'store' }
      },
      {
        path: 'products',
        loadComponent: () => import('./supplier/ingredients/supplier-ingredients/supplier-ingredients')
          .then(m => m.SupplierIngredients),
        data: { title: 'Catalogo Prodotti', icon: 'package-search' }
      },
      {
        path: 'ingredients',
        loadComponent: () => import('./supplier/ingredients/supplier-ingredients/supplier-ingredients')
          .then(m => m.SupplierIngredients),
        data: { title: 'Ingredienti', icon: 'package' }
      },
      { path: '', redirectTo: 'dashboard', pathMatch: 'full' }
    ]
  },

  // ── CUSTOMER ───────────────────────────────────────────────────
  {
    path: 'customer',
    canActivate: [AuthGuard, RoleGuard],
    data: { roles: ['customer'], context: 'customer' },
    children: [
      {
        path: 'home',
        loadComponent: () => import('./customer/home/home').then(m => m.Home),
        data: { title: 'Home', icon: 'home' }
      },
      {
        path: 'search',
        loadComponent: () => import('./customer/search/restaurant-search/restaurant-search')
          .then(m => m.RestaurantSearch),
        data: { title: 'Cerca Ristoranti', icon: 'search' }
      },
      {
        path: 'menu-display',
        loadComponent: () => import('./customer/restaurant/menu-display/menu-display')
          .then(m => m.MenuDisplay),
        data: { hideGlobalHeader: true }
      },
      {
        path: 'menu/:id',
        loadComponent: () => import('./customer/restaurant/menu-display/menu-display')
          .then(m => m.MenuDisplay),
        data: { hideGlobalHeader: true }
      },
      {
        path: 'restaurant/:restaurantId/reservation',
        loadComponent: () => import('./customer/booking/reservation-wizard/reservation-wizard')
          .then(m => m.ReservationWizard),
        data: { title: 'Prenotazione Tavolo', icon: 'calendar-check' }
      },
      {
        path: 'restaurant/:id',
        loadComponent: () => import('./customer/restaurant/restaurant-detail/restaurant-detail')
          .then(m => m.RestaurantDetail),
        data: { hideGlobalHeader: true }
      },
      {
        path: 'orders',
        loadComponent: () => import('./customer/orders/order-tracker/order-tracker')
          .then(m => m.OrderTracker),
        data: { title: 'I miei Ordini', icon: 'shopping-bag' }
      },
      {
        path: 'reviews',
        loadComponent: () => import('./customer/reviews/review-system/review-system')
          .then(m => m.ReviewSystem),
        data: { title: 'Le mie Recensioni', icon: 'star' }
      },
      {
        path: 'user-promotions',
        loadComponent: () => import('./customer/user-promotions/user-promotions.component')
          .then(m => m.UserPromotionsComponent),
        data: { title: 'Le mie Promozioni', icon: 'tag' }
      },
      {
        path: 'settings',
        loadComponent: () => import('./customer/settings-customer/settings-customer')
          .then(m => m.SettingsCustomer),
        data: { title: 'Impostazioni', icon: 'settings' }
      },
      {
        path: 'profile-user',
        loadComponent: () => import('./customer/profile-user/profile-user').then(m => m.ProfileUser),
        data: { title: 'Account', icon: 'user' }
      },
      { path: '', redirectTo: 'home', pathMatch: 'full' }
    ]
  },

  // ── FOOD COST ──────────────────────────────────────────────────
  {
    path: 'food-cost',
    loadComponent: () => import('./restaurant/foodcost-calculator/foodcost-calculator')
      .then(m => m.FoodCostCalculator),
    canActivate: [AuthGuard, StaffGuard],
    data: { permissions: ['view_ingredients'], title: 'Food Cost', icon: 'piggy-bank' }
  },
  {
    path: 'food-cost-calculator/:id',
    loadComponent: () => import('./restaurant/foodcost-calculator/foodcost-calculator')
      .then(m => m.FoodCostCalculator),
    canActivate: [AuthGuard, StaffGuard],
    data: { permissions: ['view_ingredients'], title: 'Modifica Piatto', icon: 'piggy-bank' }
  },
  {
    path: 'food-cost/ingredient/new',
    loadComponent: () => import('./restaurant/foodcost-calculator/foodcost-calculator')
      .then(m => m.FoodCostCalculator),
    canActivate: [AuthGuard, StaffGuard],
    data: { permissions: ['view_ingredients'], title: 'Crea Ingrediente', icon: 'package-plus' }
  },

  // ── FALLBACK ───────────────────────────────────────────────────
  { path: '', pathMatch: 'full', redirectTo: 'customer/home' },
  { path: '**', redirectTo: 'login' }
];